#include <stddef.h>

#include <threads.h>
#include <hardware.h>
#include <terminals.h>

#ifndef ERROR
#define ERROR (-1)
#endif

#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 1024
#endif

#define ECHO_QUEUE_CAPACITY (TERMINAL_MAX_LINE * 4 + 8)

enum tx_source {
    TX_SOURCE_NONE = 0,
    TX_SOURCE_ECHO = 1,
    TX_SOURCE_WRITE = 2
};

struct terminal_state {
    int initialized;

    struct termstat stats;

    char input_buf[TERMINAL_MAX_LINE];
    int input_head;
    int input_count;
    int complete_lines;
    int current_line_len;

    char echo_buf[ECHO_QUEUE_CAPACITY];
    int echo_head;
    int echo_count;

    int reader_active;
    int writer_active;
    int writer_complete;

    char *write_buf;
    int write_len;
    int write_pos;
    int write_need_lf;

    enum tx_source tx_source;
};

static int driver_initialized;
static struct terminal_state terminals[NUM_TERMINALS];

static cond_id_t read_turn_cv[NUM_TERMINALS];
static cond_id_t read_ready_cv[NUM_TERMINALS];
static cond_id_t write_turn_cv[NUM_TERMINALS];
static cond_id_t write_done_cv[NUM_TERMINALS];

static int
valid_term(int term)
{
    return term >= 0 && term < NUM_TERMINALS;
}

static void
reset_terminal_state(int term)
{
    struct terminal_state *ts = &terminals[term];

    ts->initialized = 1;

    ts->stats.tty_in = 0;
    ts->stats.tty_out = 0;
    ts->stats.user_in = 0;
    ts->stats.user_out = 0;

    ts->input_head = 0;
    ts->input_count = 0;
    ts->complete_lines = 0;
    ts->current_line_len = 0;

    ts->echo_head = 0;
    ts->echo_count = 0;

    ts->reader_active = 0;
    ts->writer_active = 0;
    ts->writer_complete = 0;

    ts->write_buf = NULL;
    ts->write_len = 0;
    ts->write_pos = 0;
    ts->write_need_lf = 0;

    ts->tx_source = TX_SOURCE_NONE;
}

static void
enqueue_echo_char(struct terminal_state *ts, char c)
{
    int tail;

    if (ts->echo_count >= ECHO_QUEUE_CAPACITY) {
        return;
    }

    tail = (ts->echo_head + ts->echo_count) % ECHO_QUEUE_CAPACITY;
    ts->echo_buf[tail] = c;
    ts->echo_count++;
}

static void
enqueue_echo_sequence(struct terminal_state *ts, const char *chars, int len)
{
    int i;

    for (i = 0; i < len; i++) {
        enqueue_echo_char(ts, chars[i]);
    }
}

static char
dequeue_echo_char(struct terminal_state *ts)
{
    char c = ts->echo_buf[ts->echo_head];

    ts->echo_head = (ts->echo_head + 1) % ECHO_QUEUE_CAPACITY;
    ts->echo_count--;
    return c;
}

static void
write_hardware_char(int term, struct terminal_state *ts, char c, enum tx_source source)
{
    WriteDataRegister(term, c);
    ts->stats.tty_out++;
    ts->tx_source = source;
}

static void
update_write_completion(int term)
{
    struct terminal_state *ts = &terminals[term];

    if (!ts->writer_active || ts->writer_complete) {
        return;
    }

    if (ts->write_pos == ts->write_len &&
        !ts->write_need_lf &&
        ts->tx_source != TX_SOURCE_WRITE) {
        ts->writer_complete = 1;
        CondSignal(write_done_cv[term]);
    }
}

static void
start_output_if_possible(int term)
{
    struct terminal_state *ts = &terminals[term];
    char c;

    if (!ts->initialized || ts->tx_source != TX_SOURCE_NONE) {
        return;
    }

    if (ts->echo_count > 0) {
        c = dequeue_echo_char(ts);
        write_hardware_char(term, ts, c, TX_SOURCE_ECHO);
        return;
    }

    if (!ts->writer_active || ts->writer_complete) {
        return;
    }

    if (ts->write_need_lf) {
        ts->write_need_lf = 0;
        write_hardware_char(term, ts, '\n', TX_SOURCE_WRITE);
        return;
    }

    if (ts->write_pos >= ts->write_len) {
        return;
    }

    c = ts->write_buf[ts->write_pos++];
    if (c == '\n') {
        ts->write_need_lf = 1;
        write_hardware_char(term, ts, '\r', TX_SOURCE_WRITE);
        return;
    }

    write_hardware_char(term, ts, c, TX_SOURCE_WRITE);
}

static void
append_input_char(struct terminal_state *ts, char c)
{
    int tail = (ts->input_head + ts->input_count) % TERMINAL_MAX_LINE;

    ts->input_buf[tail] = c;
    ts->input_count++;
}

static void
remove_last_input_char(struct terminal_state *ts)
{
    ts->input_count--;
}

int
InitTerminalDriver(void)
{
    int term;

    Declare_Monitor_Entry_Procedure();

    if (driver_initialized) {
        return ERROR;
    }

    for (term = 0; term < NUM_TERMINALS; term++) {
        read_turn_cv[term] = CondCreate();
        read_ready_cv[term] = CondCreate();
        write_turn_cv[term] = CondCreate();
        write_done_cv[term] = CondCreate();

        terminals[term].initialized = 0;
        terminals[term].stats.tty_in = -1;
        terminals[term].stats.tty_out = -1;
        terminals[term].stats.user_in = -1;
        terminals[term].stats.user_out = -1;
    }

    driver_initialized = 1;
    return 0;
}

int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term) || terminals[term].initialized) {
        return ERROR;
    }

    if (InitHardware(term) == ERROR) {
        return ERROR;
    }

    reset_terminal_state(term);
    return 0;
}

int
ReadTerminal(int term, char *buf, int buflen)
{
    struct terminal_state *ts;
    int copied = 0;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term) || !terminals[term].initialized ||
        buflen < 0 || (buf == NULL && buflen > 0)) {
        return ERROR;
    }

    if (buflen == 0) {
        return 0;
    }

    ts = &terminals[term];

    while (ts->reader_active) {
        CondWait(read_turn_cv[term]);
    }
    ts->reader_active = 1;

    while (ts->complete_lines == 0) {
        CondWait(read_ready_cv[term]);
    }

    while (copied < buflen && ts->input_count > 0) {
        char c = ts->input_buf[ts->input_head];

        ts->input_head = (ts->input_head + 1) % TERMINAL_MAX_LINE;
        ts->input_count--;
        buf[copied++] = c;

        if (c == '\n') {
            ts->complete_lines--;
            break;
        }
    }

    ts->stats.user_out += copied;
    ts->reader_active = 0;
    CondSignal(read_turn_cv[term]);

    return copied;
}

int
WriteTerminal(int term, char *buf, int buflen)
{
    struct terminal_state *ts;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term) || !terminals[term].initialized ||
        buflen < 0 || (buf == NULL && buflen > 0)) {
        return ERROR;
    }

    ts = &terminals[term];

    while (ts->writer_active) {
        CondWait(write_turn_cv[term]);
    }

    ts->writer_active = 1;
    ts->writer_complete = 0;
    ts->write_buf = buf;
    ts->write_len = buflen;
    ts->write_pos = 0;
    ts->write_need_lf = 0;

    ts->stats.user_in += buflen;

    update_write_completion(term);
    start_output_if_possible(term);
    update_write_completion(term);

    while (!ts->writer_complete) {
        CondWait(write_done_cv[term]);
    }

    ts->writer_active = 0;
    ts->write_buf = NULL;
    ts->write_len = 0;
    ts->write_pos = 0;
    ts->write_need_lf = 0;

    CondSignal(write_turn_cv[term]);
    start_output_if_possible(term);

    return buflen;
}

int
TerminalDriverStatistics(struct termstat *stats)
{
    int term;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || stats == NULL) {
        return ERROR;
    }

    for (term = 0; term < NUM_TERMINALS; term++) {
        stats[term] = terminals[term].stats;
    }

    return 0;
}

void
ReceiveInterrupt(int term)
{
    struct terminal_state *ts;
    char c;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term) || !terminals[term].initialized) {
        return;
    }

    ts = &terminals[term];
    c = ReadDataRegister(term);
    ts->stats.tty_in++;

    if (c == '\r' || c == '\n') {
        if (ts->input_count < TERMINAL_MAX_LINE) {
            append_input_char(ts, '\n');
            ts->complete_lines++;
            ts->current_line_len = 0;
            enqueue_echo_sequence(ts, "\r\n", 2);
            CondSignal(read_ready_cv[term]);
        }
    } else if (c == '\b' || c == '\177') {
        if (ts->current_line_len > 0) {
            remove_last_input_char(ts);
            ts->current_line_len--;
            enqueue_echo_sequence(ts, "\b \b", 3);
        }
    } else if (ts->input_count < TERMINAL_MAX_LINE) {
        append_input_char(ts, c);
        ts->current_line_len++;
        enqueue_echo_char(ts, c);
    }

    start_output_if_possible(term);
    update_write_completion(term);
}

void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || !valid_term(term) || !terminals[term].initialized) {
        return;
    }

    terminals[term].tx_source = TX_SOURCE_NONE;
    update_write_completion(term);
    start_output_if_possible(term);
    update_write_completion(term);
}

from typing import Tuple
import re


def _check_test8_strict(output: str, exit_code: int) -> Tuple[bool, str]:
    if exit_code != 0:
        return (False, f"Exit code {exit_code}")

    done_count = output.count("Done: status =")
    if done_count != 2:
        return (False, f"Expected 2 completed writers, found {done_count}")

    user_in = re.findall(r"User characters written \(user_in\): (-?\d+)", output)
    tty_out = re.findall(r"Characters out \(tty_out\): (-?\d+)", output)
    tty_in = re.findall(r"Characters in \(tty_in\): (-?\d+)", output)
    user_out = re.findall(r"User characters read \(user_out\): (-?\d+)", output)

    if not all(len(matches) >= 2 for matches in (user_in, tty_out, tty_in, user_out)):
        return (False, "Missing per-terminal statistics in output")

    if [int(user_in[0]), int(tty_out[0]), int(tty_in[0]), int(user_out[0])] != [-1, -1, -1, -1]:
        return (False, "Uninitialized terminal 0 statistics were modified")

    if int(user_in[1]) != 1446:
        return (False, f"terminal 1 user_in = {user_in[1]}, expected 1446")
    if int(tty_out[1]) != 1446:
        return (False, f"terminal 1 tty_out = {tty_out[1]}, expected 1446")
    if int(tty_in[1]) != 0:
        return (False, f"terminal 1 tty_in = {tty_in[1]}, expected 0")
    if int(user_out[1]) != 0:
        return (False, f"terminal 1 user_out = {user_out[1]}, expected 0")

    return (True, "")


TEST_DEFINITIONS = {
    "agent_test8_strict_stats": {
        "program": "test8",
        "points": 0,
        "timeout": 60,
        "check": _check_test8_strict,
        "description": "Stricter long-write statistics validation",
    },
}

